"""
Dashboard rendering engine for Crowdpulse.

Renders user dashboards with their custom content, charts, and annotations.
All user-provided HTML content is expected to be pre-sanitized before reaching
this module.
"""

from typing import List, Dict, Any, Optional
from models.user_content import UserContent, ContentType


class DashboardRenderer:
    """Renders a complete dashboard view with user content."""

    def __init__(self, dashboard_id: int):
        self.dashboard_id = dashboard_id
        self._content_cache: Dict[ContentType, str] = {}

    def render_title(self, content: UserContent) -> str:
        """Render the dashboard title section.

        Content is inserted directly into the template as it should
        already be sanitized by the security module.
        """
        return f'<div class="dashboard-title">{content.html_content}</div>'

    def render_description(self, content: UserContent) -> str:
        """Render dashboard description with rich formatting."""
        return f'<div class="dashboard-description">{content.html_content}</div>'

    def render_annotation(self, content: UserContent) -> str:
        """Render a chart annotation overlay.

        Annotations are positioned over chart areas and may contain
        formatted text with links.
        """
        return (
            f'<div class="annotation-overlay" data-id="{content.id}">'
            f'  <div class="annotation-content">{content.html_content}</div>'
            f'</div>'
        )

    def render_full(self, contents: List[UserContent]) -> str:
        """Render the complete dashboard HTML."""
        sections = []
        for content in contents:
            if content.content_type == ContentType.TITLE:
                sections.append(self.render_title(content))
            elif content.content_type == ContentType.DESCRIPTION:
                sections.append(self.render_description(content))
            elif content.content_type == ContentType.ANNOTATION:
                sections.append(self.render_annotation(content))

        return '\n'.join(sections)
